// MARK: - Native Bridge Message Types
enum NativeAction: String {
    case openCamera
    case requestCameraPermission
    case requestPushNotification
    case getPushToken
    case initiateInAppPurchase
    case restorePurchases
    case getDeviceInfo
    case hapticFeedback
    case shareContent
    case openSettings
}

// MARK: - Bridge Message Model
struct BridgeMessage {
    let action: NativeAction
    let payload: [String: Any]
    let callbackId: String?
    
    init?(from dictionary: [String: Any]) {
        guard let actionString = dictionary["action"] as? String,
              let action = NativeAction(rawValue: actionString) else {
            return nil
        }
        self.action = action
        self.payload = dictionary["payload"] as? [String: Any] ?? [:]
        self.callbackId = dictionary["callbackId"] as? String
    }
}

