    // MARK: - JavaScript Bridge Script
    private func createBridgeScript() -> String {
        return """
        (function() {
            window.NativeBridge = {
                _callbackCounter: 0,
                _callbacks: {},
                
                _generateCallbackId: function() {
                    return 'cb_' + (++this._callbackCounter) + '_' + Date.now();
                },
                
                _sendMessage: function(action, payload, callback) {
                    var message = {
                        action: action,
                        payload: payload || {}
                    };
                    
                    if (callback) {
                        var callbackId = this._generateCallbackId();
                        this._callbacks[callbackId] = callback;
                        message.callbackId = callbackId;
                    }
                    
                    window.webkit.messageHandlers.\(messageHandlerName).postMessage(message);
                },
                
                _receiveCallback: function(callbackId, success, data) {
                    var callback = this._callbacks[callbackId];
                    if (callback) {
                        callback({ success: success, data: data });
                        delete this._callbacks[callbackId];
                    }
                },
                
                // Camera
                openCamera: function(options, callback) {
                    this._sendMessage('openCamera', options, callback);
                },
                
                requestCameraPermission: function(callback) {
                    this._sendMessage('requestCameraPermission', {}, callback);
                },
                
                // Push Notifications
                requestPushNotification: function(callback) {
                    this._sendMessage('requestPushNotification', {}, callback);
                },
                
                getPushToken: function(callback) {
                    this._sendMessage('getPushToken', {}, callback);
                },
                
                // In-App Purchases
                initiateInAppPurchase: function(productId, callback) {
                    this._sendMessage('initiateInAppPurchase', { productId: productId }, callback);
                },
                
                restorePurchases: function(callback) {
                    this._sendMessage('restorePurchases', {}, callback);
                },
                
                // Device Info
                getDeviceInfo: function(callback) {
                    this._sendMessage('getDeviceInfo', {}, callback);
                },
                
                // Haptic Feedback
                hapticFeedback: function(style) {
                    this._sendMessage('hapticFeedback', { style: style || 'medium' });
                },
                
                // Share
                shareContent: function(content, callback) {
                    this._sendMessage('shareContent', content, callback);
                },
                
                // Settings
                openSettings: function() {
                    this._sendMessage('openSettings', {});
                },
                
                // Platform check
                isNative: true,
                platform: 'ios'
            };
            
            // Dispatch event so web app knows native bridge is ready
            var event = new CustomEvent('NativeBridgeReady', { detail: { platform: 'ios' } });
            document.dispatchEvent(event);
        })();
        """
    }
    
