    // MARK: Camera
    private func handleOpenCamera(_ message: BridgeMessage) {
        let status = AVCaptureDevice.authorizationStatus(for: .video)
        
        guard status == .authorized else {
            if status == .notDetermined {
                AVCaptureDevice.requestAccess(for: .video) { [weak self] granted in
                    DispatchQueue.main.async {
                        if granted {
                            self?.presentCamera(callbackId: message.callbackId)
                        } else {
                            self?.sendCallback(message.callbackId, success: false, data: ["error": "Camera access denied"])
                        }
                    }
                }
            } else {
                sendCallback(message.callbackId, success: false, data: ["error": "Camera access denied. Please enable in Settings."])
            }
            return
        }
        
        presentCamera(callbackId: message.callbackId)
    }
    
    private func presentCamera(callbackId: String?) {
        guard UIImagePickerController.isSourceTypeAvailable(.camera) else {
            sendCallback(callbackId, success: false, data: ["error": "Camera not available"])
            return
        }
        
        let picker = UIImagePickerController()
        picker.sourceType = .camera
        picker.delegate = self
        picker.allowsEditing = true
        // Store callback ID for later use
        objc_setAssociatedObject(picker, "callbackId", callbackId, .OBJC_ASSOCIATION_RETAIN)
        present(picker, animated: true)
    }
    
    private func handleCameraPermission(_ message: BridgeMessage) {
        let status = AVCaptureDevice.authorizationStatus(for: .video)
        
        switch status {
        case .authorized:
            sendCallback(message.callbackId, success: true, data: ["status": "authorized"])
        case .notDetermined:
            AVCaptureDevice.requestAccess(for: .video) { [weak self] granted in
                DispatchQueue.main.async {
                    self?.sendCallback(message.callbackId, success: true, data: ["status": granted ? "authorized" : "denied"])
                }
            }
        case .denied, .restricted:
            sendCallback(message.callbackId, success: true, data: ["status": "denied"])
        @unknown default:
            sendCallback(message.callbackId, success: false, data: ["status": "unknown"])
        }
    }
    
    // MARK: Push Notifications
    private func handlePushNotificationRequest(_ message: BridgeMessage) {
        UNUserNotificationCenter.current().requestAuthorization(options: [.alert, .badge, .sound]) { [weak self] granted, error in
            DispatchQueue.main.async {
                if granted {
                    UIApplication.shared.registerForRemoteNotifications()
                    self?.sendCallback(message.callbackId, success: true, data: ["granted": true])
                } else {
                    let errorMessage = error?.localizedDescription ?? "Permission denied"
                    self?.sendCallback(message.callbackId, success: false, data: ["granted": false, "error": errorMessage])
                }
            }
        }
    }
    
    private func handleGetPushToken(_ message: BridgeMessage) {
        if let token = pushToken {
            sendCallback(message.callbackId, success: true, data: ["token": token])
        } else {
            sendCallback(message.callbackId, success: false, data: ["error": "Push token not available"])
        }
    }
    
    func updatePushToken(_ token: String) {
        self.pushToken = token
        // Notify web app of token update
        executeJavaScript("if(window.NativeBridge && window.NativeBridge.onPushTokenUpdated) { window.NativeBridge.onPushTokenUpdated('\(token)'); }")
    }
    
    func handlePushNotificationReceived(_ userInfo: [AnyHashable: Any]) {
        if let jsonData = try? JSONSerialization.data(withJSONObject: userInfo),
           let jsonString = String(data: jsonData, encoding: .utf8) {
            executeJavaScript("if(window.NativeBridge && window.NativeBridge.onPushNotificationReceived) { window.NativeBridge.onPushNotificationReceived(\(jsonString)); }")
        }
    }
    
    // MARK: In-App Purchases
    private func handleInAppPurchase(_ message: BridgeMessage) {
        guard let productId = message.payload["productId"] as? String else {
            sendCallback(message.callbackId, success: false, data: ["error": "Product ID required"])
            return
        }
        
        guard SKPaymentQueue.canMakePayments() else {
            sendCallback(message.callbackId, success: false, data: ["error": "In-app purchases are disabled"])
            return
        }
        
        pendingPurchaseCallbackId = message.callbackId
        
        // Check if product is already fetched
        if let product = availableProducts.first(where: { $0.productIdentifier == productId }) {
            let payment = SKPayment(product: product)
            SKPaymentQueue.default().add(payment)
        } else {
            // Fetch product first
            let request = SKProductsRequest(productIdentifiers: Set([productId]))
            request.delegate = self
            productsRequest = request
            request.start()
        }
    }
    
    private func handleRestorePurchases(_ message: BridgeMessage) {
        pendingPurchaseCallbackId = message.callbackId
        SKPaymentQueue.default().restoreCompletedTransactions()
    }
    
    // MARK: Device Info
    private func handleGetDeviceInfo(_ message: BridgeMessage) {
        let device = UIDevice.current
        let info: [String: Any] = [
            "model": device.model,
            "systemName": device.systemName,
            "systemVersion": device.systemVersion,
            "name": device.name,
            "identifierForVendor": device.identifierForVendor?.uuidString ?? "unknown",
            "batteryLevel": device.batteryLevel,
            "screenWidth": UIScreen.main.bounds.width,
            "screenHeight": UIScreen.main.bounds.height,
            "screenScale": UIScreen.main.scale,
            "appVersion": Bundle.main.infoDictionary?["CFBundleShortVersionString"] as? String ?? "unknown",
            "buildNumber": Bundle.main.infoDictionary?["CFBundleVersion"] as? String ?? "unknown",
            "safeAreaTop": view.safeAreaInsets.top,
            "safeAreaBottom": view.safeAreaInsets.bottom
        ]
        sendCallback(message.callbackId, success: true, data: info)
    }
    
    // MARK: Haptic Feedback
    private func handleHapticFeedback(_ message: BridgeMessage) {
        let style = message.payload["style"] as? String ?? "medium"
        
        switch style {
        case "light":
            let generator = UIImpactFeedbackGenerator(style: .light)
            generator.impactOccurred()
        case "medium":
            let generator = UIImpactFeedbackGenerator(style: .medium)
            generator.impactOccurred()
        case "heavy":
            let generator = UIImpactFeedbackGenerator(style: .heavy)
            generator.impactOccurred()
        case "success":
            let generator = UINotificationFeedbackGenerator()
            generator.notificationOccurred(.success)
        case "warning":
            let generator = UINotificationFeedbackGenerator()
            generator.notificationOccurred(.warning)
        case "error":
            let generator = UINotificationFeedbackGenerator()
            generator.notificationOccurred(.error)
        case "selection":
            let generator = UISelectionFeedbackGenerator()
            generator.selectionChanged()
        default:
            let generator = UIImpactFeedbackGenerator(style: .medium)
            generator.impactOccurred()
        }
    }
    
    // MARK: Share Content
    private func handleShareContent(_ message: BridgeMessage) {
        var items: [Any] = []
        
        if let text = message.payload["text"] as? String {
            items.append(text)
        }
        if let urlString = message.payload["url"] as? String, let url = URL(string: urlString) {
            items.append(url)
        }
        
        guard !items.isEmpty else {
            sendCallback(message.callbackId, success: false, data: ["error": "No content to share"])
            return
        }
        
        let activityVC = UIActivityViewController(activityItems: items, applicationActivities: nil)
        activityVC.completionWithItemsHandler = { [weak self] activityType, completed, _, error in
            if let error = error {
                self?.sendCallback(message.callbackId, success: false, data: ["error": error.localizedDescription])
            } else {
                self?.sendCallback(message.callbackId, success: true, data: [
                    "completed": completed,
                    "activityType": activityType?.rawValue ?? ""
                ])
            }
        }
        
        // iPad support
        if let popover = activityVC.popoverPresentationController {
            popover.sourceView = view
            popover.sourceRect = CGRect(x: view.bounds.midX, y: view.bounds.midY, width: 0, height: 0)
        }
        
        present(activityVC, animated: true)
    }
    
    // MARK: Open Settings
    private func handleOpenSettings() {
        if let settingsURL = URL(string: UIApplication.openSettingsURLString) {
            UIApplication.shared.open(settingsURL)
        }
    }
    
    // MARK: - Helper Methods
    private func sendCallback(_ callbackId: String?, success: Bool, data: [String: Any]) {
        guard let callbackId = callbackId else { return }
        
        do {
            let jsonData = try JSONSerialization.data(withJSONObject: data)
            let jsonString = String(data: jsonData, encoding: .utf8) ?? "{}"
            let script = "window.NativeBridge._receiveCallback('\(callbackId)', \(success), \(jsonString));"
            executeJavaScript(script)
        } catch {
            let script = "window.NativeBridge._receiveCallback('\(callbackId)', false, {\"error\": \"Serialization error\"});"
            executeJavaScript(script)
        }
    }
    
    private func executeJavaScript(_ script: String) {
        DispatchQueue.main.async { [weak self] in
            self?.webView.evaluateJavaScript(script) { _, error in
                if let error = error {
                    print("[NativeBridge] JS execution error: \(error.localizedDescription)")
                }
            }
        }
    }
    
    private func showErrorAlert(message: String) {
        let alert = UIAlertController(title: "Error", message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "Retry", style: .default) { [weak self] _ in
            self?.loadWebsite()
        })
        alert.addAction(UIAlertAction(title: "OK", style: .cancel))
        present(alert, animated: true)
    }
    
    // MARK: - Public Methods
    func goBack() {
        if webView.canGoBack {
            webView.goBack()
        }
    }
    
    func goForward() {
        if webView.canGoForward {
            webView.goForward()
        }
    }
    
    func reload() {
        webView.reload()
    }
}

// MARK: - WKScriptMessageHandler
extension HybridWebViewController: WKScriptMessageHandler {
    func userContentController(_ userContentController: WKUserContentController, didReceive message: WKScriptMessage) {
        guard message.name == messageHandlerName,
              let body = message.body as? [String: Any],
              let bridgeMessage = BridgeMessage(from: body) else {
            print("[NativeBridge] Invalid message received")
            return
        }
        
        print("[NativeBridge] Received action: \(bridgeMessage.action.rawValue)")
        handleNativeAction(bridgeMessage)
    }
}

// MARK: - WKNavigationDelegate
extension HybridWebViewController: WKNavigationDelegate {
    func webView(_ webView: WKWebView, didStartProvisionalNavigation navigation: WKNavigation!) {
        activityIndicator.startAnimating()
        progressView.isHidden = false
    }
    
    func webView(_ webView: WKWebView, didFinish navigation: WKNavigation!) {
        activityIndicator.stopAnimating()
        progressView.isHidden = true
    }
    
    func webView(_ webView: WKWebView, didFail navigation: WKNavigation!, withError error: Error) {
        activityIndicator.stopAnimating()
        progressView.isHidden = true
        
        let nsError = error as NSError
        // Ignore cancelled navigation errors
        if nsError.code != NSURLErrorCancelled {
            showErrorAlert(message: "Failed to load page: \(error.localizedDescription)")
        }
    }
    
    func webView(_ webView: WKWebView, didFailProvisionalNavigation navigation: WKNavigation!, withError error: Error) {
        activityIndicator.stopAnimating()
        progressView.isHidden = true
        
        let nsError = error as NSError
        if nsError.code == NSURLErrorNotConnectedToInternet {
            showErrorAlert(message: "No internet connection. Please check your network settings.")
        } else if nsError.code != NSURLErrorCancelled {
            showErrorAlert(message: "Failed to load: \(error.localizedDescription)")
        }
    }
    
    func webView(_ webView: WKWebView, decidePolicyFor navigationAction: WKNavigationAction, decisionHandler: @escaping (WKNavigationActionPolicy) -> Void) {
        guard let url = navigationAction.request.url else {
            decisionHandler(.cancel)
            return
        }
        
        // Handle external links (tel:, mailto:, etc.)
        let scheme = url.scheme ?? ""
        if ["tel", "mailto", "sms", "facetime"].contains(scheme) {
            UIApplication.shared.open(url)
            decisionHandler(.cancel)
            return
        }
        
        // Handle App Store links
        if url.host?.contains("itunes.apple.com") == true || url.host?.contains("apps.apple.com") == true {
            UIApplication.shared.open(url)
            decisionHandler(.cancel)
            return
        }
        
        // Handle external URLs - open in Safari
        if let host = url.host, let baseHost = URL(string: baseURL)?.host, host != baseHost {
            if navigationAction.navigationType == .linkActivated {
                UIApplication.shared.open(url)
                decisionHandler(.cancel)
                return
            }
        }
        
        decisionHandler(.allow)
    }
    
    func webView(_ webView: WKWebView, decidePolicyFor navigationResponse: WKNavigationResponse, decisionHandler: @escaping (WKNavigationResponsePolicy) -> Void) {
        decisionHandler(.allow)
    }
}

// MARK: - WKUIDelegate
extension HybridWebViewController: WKUIDelegate {
    // Handle JavaScript alerts
    func webView(_ webView: WKWebView, runJavaScriptAlertPanelWithMessage message: String, initiatedByFrame frame: WKFrameInfo, completionHandler: @escaping () -> Void) {
        let alert = UIAlertController(title: nil, message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default) { _ in
            completionHandler()
        })
        present(alert, animated: true)
    }
    
    // Handle JavaScript confirms
    func webView(_ webView: WKWebView, runJavaScriptConfirmPanelWithMessage message: String, initiatedByFrame frame: WKFrameInfo, completionHandler: @escaping (Bool) -> Void) {
        let alert = UIAlertController(title: nil, message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel) { _ in
            completionHandler(false)
        })
        alert.addAction(UIAlertAction(title: "OK", style: .default) { _ in
            completionHandler(true)
        })
        present(alert, animated: true)
    }
    
    // Handle JavaScript prompts
    func webView(_ webView: WKWebView, runJavaScriptTextInputPanelWithPrompt prompt: String, defaultText: String?, initiatedByFrame frame: WKFrameInfo, completionHandler: @escaping (String?) -> Void) {
        let alert = UIAlertController(title: nil, message: prompt, preferredStyle: .alert)
        alert.addTextField { textField in
            textField.text = defaultText
        }
        alert.addAction(UIAlertAction(title: "Cancel", style: .cancel) { _ in
            completionHandler(nil)
        })
        alert.addAction(UIAlertAction(title: "OK", style: .default) { _ in
            completionHandler(alert.textFields?.first?.text)
        })
        present(alert, animated: true)
    }
    
    // Handle new window requests (target="_blank")
    func webView(_ webView: WKWebView, createWebViewWith configuration: WKWebViewConfiguration, for navigationAction: WKNavigationAction, windowFeatures: WKWindowFeatures) -> WKWebView? {
        if navigationAction.targetFrame == nil || !navigationAction.targetFrame!.isMainFrame {
            webView.load(navigationAction.request)
        }
        return nil
    }
}

// MARK: - UIImagePickerControllerDelegate
extension HybridWebViewController: UIImagePickerControllerDelegate, UINavigationControllerDelegate {
    func imagePickerController(_ picker: UIImagePickerController, didFinishPickingMediaWithInfo info: [UIImagePickerController.InfoKey : Any]) {
        let callbackId = objc_getAssociatedObject(picker, "callbackId") as? String
        
        picker.dismiss(animated: true) { [weak self] in
            guard let image = info[.editedImage] as? UIImage ?? info[.originalImage] as? UIImage else {
                self?.sendCallback(callbackId, success: false, data: ["error": "Failed to capture image"])
                return
            }
            
            // Convert image to base64
            if let imageData = image.jpegData(compressionQuality: 0.8) {
                let base64String = imageData.base64EncodedString()
                self?.sendCallback(callbackId, success: true, data: [
                    "imageBase64": "data:image/jpeg;base64,\(base64String)",
                    "width": image.size.width,
                    "height": image.size.height
                ])
            } else {
                self?.sendCallback(callbackId, success: false, data: ["error": "Failed to process image"])
            }
        }
    }
    
    func imagePickerControllerDidCancel(_ picker: UIImagePickerController) {
        let callbackId = objc_getAssociatedObject(picker, "callbackId") as? String
        picker.dismiss(animated: true) { [weak self] in
            self?.sendCallback(callbackId, success: false, data: ["error": "User cancelled"])
        }
    }
}

// MARK: - SKProductsRequestDelegate
extension HybridWebViewController: SKProductsRequestDelegate {
    func productsRequest(_ request: SKProductsRequest, didReceive response: SKProductsResponse) {
        availableProducts.append(contentsOf: response.products)
        
        if let product = response.products.first {
            let payment = SKPayment(product: product)
            SKPaymentQueue.default().add(payment)
        } else {
            sendCallback(pendingPurchaseCallbackId, success: false, data: ["error": "Product not found"])
            pendingPurchaseCallbackId = nil
        }
    }
    
    func request(_ request: SKRequest, didFailWithError error: Error) {
        sendCallback(pendingPurchaseCallbackId, success: false, data: ["error": error.localizedDescription])
        pendingPurchaseCallbackId = nil
    }
}

// MARK: - SKPaymentTransactionObserver
extension HybridWebViewController: SKPaymentTransactionObserver {
    func paymentQueue(_ queue: SKPaymentQueue, updatedTransactions transactions: [SKPaymentTransaction]) {
        for transaction in transactions {
            switch transaction.transactionState {
            case .purchased:
                let receiptData = Bundle.main.appStoreReceiptURL.flatMap { try? Data(contentsOf: $0) }
                let receiptString = receiptData?.base64EncodedString() ?? ""
                
                sendCallback(pendingPurchaseCallbackId, success: true, data: [
                    "productId": transaction.payment.productIdentifier,
                    "transactionId": transaction.transactionIdentifier ?? "",
                    "receipt": receiptString,
                    "state": "purchased"
                ])
                
                // Notify web app via event
                executeJavaScript("""
                    if(window.NativeBridge && window.NativeBridge.onPurchaseCompleted) {
                        window.NativeBridge.onPurchaseCompleted({
                            productId: '\(transaction.payment.productIdentifier)',
                            transactionId: '\(transaction.transactionIdentifier ?? "")',
                            state: 'purchased'
                        });
                    }
                """)
                
                SKPaymentQueue.default().finishTransaction(transaction)
                pendingPurchaseCallbackId = nil
                
            case .failed:
                let errorMessage = transaction.error?.localizedDescription ?? "Purchase failed"
                sendCallback(pendingPurchaseCallbackId, success: false, data: [
                    "error": errorMessage,
                    "productId": transaction.payment.productIdentifier,
                    "state": "failed"
                ])
                SKPaymentQueue.default().finishTransaction(transaction)
                pendingPurchaseCallbackId = nil
                
            case .restored:
                sendCallback(pendingPurchaseCallbackId, success: true, data: [
                    "productId": transaction.payment.productIdentifier,
                    "transactionId": transaction.transactionIdentifier ?? "",
                    "originalTransactionId": transaction.original?.transactionIdentifier ?? "",
                    "state": "restored"
                ])
                SKPaymentQueue.default().finishTransaction(transaction)
                
            case .deferred:
                sendCallback(pendingPurchaseCallbackId, success: true, data: [
                    "productId": transaction.payment.productIdentifier,
                    "state": "deferred"
                ])
                
            case .purchasing:
                break
                
            @unknown default:
                break
            }
        }
    }
    
    func paymentQueueRestoreCompletedTransactionsFinished(_ queue: SKPaymentQueue) {
        if queue.transactions.isEmpty {
            sendCallback(pendingPurchaseCallbackId, success: true, data: ["message": "No purchases to restore", "restored": []])
        }
        pendingPurchaseCallbackId = nil
    }
    
    func paymentQueue(_ queue: SKPaymentQueue, restoreCompletedTransactionsFailedWithError error: Error) {
        sendCallback(pendingPurchaseCallbackId, success: false, data: ["error": error.localizedDescription])
        pendingPurchaseCallbackId = nil
    }
}

